    val landEndTimes = landStartTime.mapIndexed { i, startTime ->
        max(startTime, startTime + landDuration[i])
    }

    val waterEndTimes = waterStartTime.mapIndexed { j, startTime ->
        max(startTime, startTime + waterDuration[j])
    }

    // Check all possible combinations of one land and one water attraction
    var minEndTime = Long.MAX_VALUE
    for (landEnd in landEndTimes) {
        for (waterEnd in waterEndTimes) {
            // If the land attraction ends before the water starts, the water can start immediately
            val maxTime = if (waterEnd >= landEnd) waterEnd else landEnd
            minEndTime = min(minEndTime, maxTime)
        }
    }

    return minEndTime
}
